import{_ as a,c as l,g as e,o as n}from"./chunks/framework.CCxIPCIe.js";const u=JSON.parse('{"title":"四〇四","description":"","frontmatter":{"title":"四〇四","date":"2026-03-02T09:39:44.231Z","length":"555字","time":"2分钟","aside":false,"hash":-1634118927},"headers":[],"relativePath":"idea/404.md","filePath":"idea/404.md"}'),s={name:"idea/404.md"};function r(o,t,d,i,p,c){return n(),l("div",null,t[0]||(t[0]=[e("p",null,"没有所谓的性压抑，而只有力比多压抑。耗散的力比多正是以性的方式被中心化压抑后，人的意识域才清空，力比多才得以有的放矢的将其投射在某个具体的对象上，对应于意识的聚焦。",-1),e("p",null,"因此性器是一把锁，但它并非是生理性的而是符号性的锁。它锁住了力比多保证它不耗散，使人的意识淹没在感性杂多中。同时使人区别于有周期性发情期的动物，人超越了动物发情的生理节律，而代之以可通过特定审美图式触发的符号节律。",-1),e("p",null,"而性活动则是这种符号活动之一，它可以打开这把力比多的锁，使力比多涣散、使意识陷入混沌，回到前符号状态的感性杂多中，这种逼近意识迷失体验到的爽感，即原乐，它是一种意识结构去符号化的崩解体验，包藏着生命回归无机状态的死亡冲动。",-1),e("p",null,"因此性是死亡，性并没有是我们抵达对方，而是回归无机状态，在这个意义上性与爱脱钩了，它不是向往爱的那种力比多持续凝聚、投注的状态，而是向往力比多的耗散，而爱的凝聚反而为性的耗散所利用，因为它最大化了那种差异体验。",-1),e("p",null,"那一则圣经寓言颇耐人寻味，亚当夏娃是吃了智慧果实发现自己赤身裸体感到羞愧。实际上这两件事恰恰是同时发生的，正因为力比多以性的方式中心化/压抑，才同时澄清了意识域发展智慧，并将这种中心化解释为一种符号上的禁忌以稳固这种压抑（对赤身裸体感到羞愧）。而赤身裸体的人往往被叫做精神病，它不仅是在区别于正常人意义上的“精神病”，也是在精神分析意义上的无法凝聚其稳固意识焦点、符号学结构瓦解的真正精神病。",-1)]))}const _=a(s,[["render",r]]);export{u as __pageData,_ as default};
